module top_module(F_in, wEnable, enable_reset, clk, r);input [4:0] F_in;
	 input clk, wEnable, enable_reset;
	 output reg [4:0] r;

 always @( posedge clk )
	begin
	if (enable_reset) r <= 5'b00000;
	else
		begin			
			if (wEnable)
				begin
					r <= F_in;
				end
			else
				begin
					r <= r;
				end
		end
	end
endmodule
